public static int[][] makeMirror(int[][] a)
{
    int[][] result = new int[a.length][a[0].length];
    for (int r = 0; r < a.length; r++)
    {
        for (int c = 0; c < a[0].length; c++)
        {
            result[r][c] = a[r][a[0].length - 1 - c];
        }
    }
    return result;
}
```

