public static int[][] change(int[][] nums)
{
    int[][] result = new int[nums.length][nums[0].length];

    for (int row = 0; row < nums.length; row++)
    {
        for (int col = 0; col < nums[0].length; col++)
        {
            result[row][col] = nums[row][col] + row - col;
        }
    }

